/// <summary>
/// Extension of the <c>SalesAgreementHeader</c> table for the ETGSPAIN model.
/// </summary>
[ExtensionOf(tablestr(SalesAgreementHeader))]
final class SalesAgreementHeaderETGSPAIN_Extension
{    
}

Method.Source:
/// <summary>
/// Initializes the table data from the Operations table.
/// </summary>
/// <param name="_ETGSPAINPurchOperationTable">ETGSPAINPurchOperationTable.</param>
void initFromETGSPAINSalesOperationTable(ETGSPAINPurchOperationTable _ETGSPAINPurchOperationTable)
{
    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        this.ETGSPAINAgreementOperationId = _ETGSPAINPurchOperationTable.OperationId;
    }
}

/// <summary>
/// Finds the specific record in the <c>SalesAgreementHeader</c> table using its Operation ID.
/// </summary>
/// <param name="_ETGSPAINOperationId">
/// The <c>ETGSPAINOperationId</c> ID of the record to find.
/// </param>
/// <param name="_forUpdate">
/// A <c>Boolean</c> value indicating whether the record is for reading or writing; optional.
/// </param>
/// <returns>
/// A record from the <c>SalesAgreementHeader</c> table; otherwise, an empty record.
/// </returns>
static SalesAgreementHeader ETGSPAINfindETGSPAINOperationId(ETGSPAINPurchOperationId   _ETGSPAINPurchOperationId,
                                                    boolean             _forUpdate = false)
{
    SalesAgreementHeader    salesAgreementHeader;

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        if (_ETGSPAINPurchOperationId)
        {
            if (_forUpdate)
            {
                salesAgreementHeader.selectForUpdate(_forUpdate);
            }

            select firstonly salesAgreementHeader
            where salesAgreementHeader.ETGSPAINAgreementOperationId     == _ETGSPAINPurchOperationId;
        }
    }

    return salesAgreementHeader;
}

/// <summary>
/// Method to change the <c>Mandatory</c> property of certain fields when agreements use Operations.
/// </summary>
/// <remarks>
/// It is important that some fields are mandatory when creating agreements that use Operations.
/// </remarks>
public static void ETGSPAINmandatoryOperationFields(FormRun _formRun)
{
    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        SalesAgreementHeader    salesAgreementHeader    = _formRun.dataSource().cursor() as SalesAgreementHeader;

        _formRun.dataSource().object(fieldNum(SalesAgreementHeader, DefaultAgreementLineExpirationDate)).mandatory((salesAgreementHeader.ETGSPAINAgreementOperationId != ""));
    }
}
